const input = $input.first().json;
const { token, import_id, type, marketplace_url, api_key } = input.body || input;

// Validate required fields
if (!token) {
  return [{ json: { error: true, code: 'MISSING_TOKEN', message: 'Token is required' } }];
}
if (!import_id) {
  return [{ json: { error: true, code: 'MISSING_IMPORT_ID', message: 'import_id is required' } }];
}
if (!type || !['products', 'offers'].includes(type)) {
  return [{ json: { error: true, code: 'INVALID_TYPE', message: 'type must be "products" or "offers"' } }];
}
if (!marketplace_url) {
  return [{ json: { error: true, code: 'MISSING_URL', message: 'marketplace_url is required' } }];
}
if (!api_key) {
  return [{ json: { error: true, code: 'MISSING_API_KEY', message: 'api_key is required' } }];
}

// Decode JWT
try {
  const parts = token.split('.');
  if (parts.length !== 3) throw new Error('Invalid token format');
  const payload = JSON.parse(Buffer.from(parts[1], 'base64url').toString());

  if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) {
    return [{ json: { error: true, code: 'TOKEN_EXPIRED', message: 'Token has expired' } }];
  }

  const vendor_id = payload.sub || payload.vendor_id || payload.user_id;
  if (!vendor_id) {
    return [{ json: { error: true, code: 'INVALID_TOKEN', message: 'Token missing subject' } }];
  }

  return [{ json: {
    error: false,
    vendor_id,
    import_id,
    type,
    marketplace_url: marketplace_url.replace(/\/$/, ''),
    api_key
  } }];
} catch (e) {
  return [{ json: { error: true, code: 'AUTH_FAILED', message: 'Token verification failed: ' + e.message } }];
}

const input = $input.first().json;
const authData = $('Verify Token & Validate').first().json;

const statusCode = input.statusCode || input.status;

if (!statusCode || statusCode < 200 || statusCode >= 300) {
  return [{ json: {
    api_success: false,
    vendor_id: authData.vendor_id,
    import_id: authData.import_id,
    type: authData.type,
    status: 'ERROR',
    error_message: input.body?.message || input.message || `Mirakl API returned ${statusCode}`,
    total: 0,
    created: 0,
    updated: 0,
    errors: [],
    has_errors: false
  } }];
}

const body = input.body || input.data || input;

// Mirakl import status response structure
// For products: { import_id, status, lines_read, lines_in_success, lines_in_error, ... }
// For offers: { import_id, status, lines_read, lines_in_success, lines_in_error, ... }
const importStatus = body.status || body.import_status || 'UNKNOWN';

// Map Mirakl status to our status
let normalizedStatus;
switch (importStatus.toUpperCase()) {
  case 'WAITING':
  case 'QUEUED':
    normalizedStatus = 'WAITING';
    break;
  case 'RUNNING':
  case 'PROCESSING':
    normalizedStatus = 'RUNNING';
    break;
  case 'COMPLETE':
  case 'COMPLETED':
  case 'SENT':
    normalizedStatus = 'COMPLETE';
    break;
  case 'FAILED':
  case 'ERROR':
    normalizedStatus = 'FAILED';
    break;
  default:
    normalizedStatus = importStatus;
}

const total = body.lines_read || body.total_count || 0;
const created = body.lines_in_success || body.success_count || 0;
const updated = body.lines_updated || 0;
const errorCount = body.lines_in_error || body.error_count || 0;

// Parse error details if available
let errors = [];
if (body.errors && Array.isArray(body.errors)) {
  errors = body.errors.map(e => ({
    sku: e.sku || e.shop_sku || e.identifier || 'unknown',
    message: e.message || e.error_message || e.reason || 'Unknown error',
    code: e.code || e.error_code || null,
    line: e.line_number || e.line || null
  }));
}
if (body.lines_in_error_details && Array.isArray(body.lines_in_error_details)) {
  errors = body.lines_in_error_details.map(e => ({
    sku: e.sku || e.identifier || 'unknown',
    message: e.message || e.error || 'Unknown error',
    code: e.code || null,
    line: e.line || null
  }));
}

return [{ json: {
  api_success: true,
  vendor_id: authData.vendor_id,
  import_id: authData.import_id,
  type: authData.type,
  status: normalizedStatus,
  total,
  created,
  updated,
  error_count: errorCount,
  errors: errors.slice(0, 100),
  has_errors: errorCount > 0,
  raw_status: importStatus
} }];

const status = $('Parse Status').first().json;

if (!status.api_success) {
  return [{ json: {
    success: false,
    error: 'mirakl_api_error',
    message: status.error_message,
    import_id: status.import_id,
    type: status.type
  } }];
}

return [{ json: {
  success: true,
  import_id: status.import_id,
  type: status.type,
  status: status.status,
  total: status.total,
  created: status.created,
  updated: status.updated,
  error_count: status.error_count,
  errors: status.errors,
  is_complete: ['COMPLETE', 'FAILED'].includes(status.status)
} }];
